private static String getImmediatePredecessor(String value) 
{
    verify(!value.isEmpty(), "value is empty");

    int lastCodePointOffset = value.offsetByCodePoints(value.length(), -1);
    int lastCodePoint = value.codePointAt(lastCodePointOffset);
    String prefix = value.substring(0, lastCodePointOffset);

    if (lastCodePoint > 0) {
        // Decrement the last character: "Apple" -> "Appld"
        // This is much "closer" than "Appl"
        return prefix + new String(Character.toChars(lastCodePoint - 1));
    }
    // If the last character is U+0000, the prefix is indeed the closest
    return prefix;
}
```
